import{_ as s,o as i,c as r,a2 as t}from"./chunks/framework.Cuq8tsM6.js";const m=JSON.parse('{"title":"Impression & Logistique","description":"","frontmatter":{"title":"Impression & Logistique"},"headers":[],"relativePath":"docs/fr/advertisers/printing-services.md","filePath":"docs/fr/advertisers/printing-services.md"}'),a={name:"docs/fr/advertisers/printing-services.md"};function o(n,e,d,l,p,u){return i(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="services-d-impression-et-logistique" tabindex="-1">Services d&#39;Impression et Logistique <a class="header-anchor" href="#services-d-impression-et-logistique" aria-label="Permalink to &quot;Services d&#39;Impression et Logistique&quot;">​</a></h1><p>getinside agit comme une centrale d&#39;achat pour mutualiser les volumes, réduire vos coûts et garantir une production responsable.</p><hr class="my-6"><h2 class="text-blue-200 mb-4">🏭 Une qualité certifiée</h2><div style="background:var(--gi-tint-green-bg);border:1px solid var(--gi-tint-green-text);border-radius:8px;padding:24px;margin-bottom:40px;"><p class="fs-4 mt-0 mb-4 text-green-200">Nous travaillons exclusivement avec un réseau de partenaires français engagés :</p><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(200px, 1fr));gap:20px;"><div style="text-align:center;"><div style="font-size:32px;margin-bottom:10px;">🇫🇷</div><strong>Made in France</strong><br><span class="fs-2">100% de la production en ateliers français.</span></div><div style="text-align:center;"><div style="font-size:32px;margin-bottom:10px;">🌱</div><strong>Éco-responsabilité</strong><br><span class="fs-2">Certification Imprim’Vert &amp; Encres végétales.</span></div><div style="text-align:center;"><div style="font-size:32px;margin-bottom:10px;">✅</div><strong>Normes ISO</strong><br><span class="fs-2">ISO 9001 (Qualité) et ISO 14001 (Environnement).</span></div></div></div><h2 class="text-blue-200 mb-4">🚀 Cas d&#39;usage &amp; Offres</h2><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(300px, 1fr));gap:20px;margin-bottom:40px;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;"><h3 class="mt-0 fs-4 text-grey-dk-000">1. Pour vos campagnes (Sponsored Mail)</h3><p>Vous réservez une campagne chez un distributeur partenaire.</p><ul><li>Nous imprimons vos supports.</li><li>Nous gérons l&#39;assemblage (ex: point de colle fugitive pour échantillon).</li><li>Nous livrons directement à l&#39;entrepôt du distributeur.</li></ul></div><div style="border:2px solid var(--gi-accent);border-radius:8px;padding:24px;background:var(--gi-tint-blue-bg);"><h3 class="mt-0 fs-4 text-purple-200">2. Auto-promotion (Pour vous)</h3><p>Vous souhaitez imprimer vos propres cartes de remerciement ou flyers à insérer dans <strong>vos propres colis</strong> ?</p><ul><li>Créez une campagne &quot;interne&quot; via la plateforme.</li><li>Bénéficiez de nos tarifs de groupe industriels.</li><li>Nous livrons les palettes chez vous.</li></ul></div></div><h2 class="text-grey-dk-000 mb-4">Modèle Économique</h2><div style="display:flex;gap:20px;flex-wrap:wrap;"><div style="flex:1;border:1px solid var(--vp-c-divider);padding:20px;border-radius:6px;"><strong>💎 Transparence</strong><br> Le coût est affiché clairement lors de la configuration. </div><div style="flex:1;border:1px solid var(--vp-c-divider);padding:20px;border-radius:6px;"><strong>📦 Tout inclus</strong><br> Impression + Façonnage + Transport. </div><div style="flex:1;border:1px solid var(--vp-c-divider);padding:20px;border-radius:6px;"><strong>📉 Économies d&#39;échelle</strong><br> Plus le volume est important, plus le coût unitaire baisse. </div></div><h2 class="text-purple-200 mb-4">Focus : Notre engagement Handicap</h2><div style="display:flex;gap:20px;flex-wrap:wrap;margin-bottom:40px;"><div style="flex:1;border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3 class="mt-0">Partenariat Exclusif</h3><p class="fs-2 text-grey-dk-000"> Pour toutes les opérations manuelles (assemblage, collage d&#39;échantillons, mise sous pli), nous travaillons exclusivement avec des <strong>Entreprises Adaptées (EA)</strong>. </p><p class="fs-2 text-grey-dk-000 mb-0"> Ces structures emploient au moins <strong>80% de travailleurs en situation de handicap</strong> dans leurs effectifs de production. </p></div><div style="flex:1;border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3 class="mt-0">Impact Social</h3><p class="fs-2 text-grey-dk-000"> En confiant votre logistique à getinside, vous soutenez directement l&#39;insertion professionnelle et sociale de personnes souvent éloignées du marché du travail. </p><p class="fs-2 text-grey-dk-000 mb-0"> Nos partenaires œuvrent notamment pour maintenir l&#39;emploi en milieu rural et accompagner la montée en compétences de leurs salariés. </p></div></div><div class="mt-6 p-4 bg-grey-lt-000 border rounded-1"><h4 class="mt-0">Comment commander ?</h4><p class="mb-2">L&#39;option d&#39;impression vous est proposée automatiquement lors de la création d&#39;une campagne sur le SaaS.</p><p class="mb-0">Pour une demande spécifique (formats spéciaux) : <a href="mailto:studio@getinside.fr">studio@getinside.fr</a></p></div>',12)])])}const v=s(a,[["render",o]]);export{m as __pageData,v as default};
